sql:
SELECT sentence_id, verb_id
FROM sentences
WHERE verb_id = (SELECT verb_id FROM verbs WHERE verb_name = 'to be');

SELECT DISTINCT v.verb_name
FROM sentences s
JOIN verbs v ON s.verb_id = v.verb_id;

SELECT DISTINCT users.user_name
FROM users
JOIN sentences ON users.user_id = sentences.created_by;

SELECT DISTINCT s.sentence_id, s.DOsentence
FROM sentences s
WHERE s.DOsentence LIKE '%book%' AND s.DOsentence LIKE '%food%';

external_knowledge:
- In this context, a "plural sentence" refers to a sentence where the subject is a plural noun; 
- A "direct object structure" refers to a sentence that contains a direct object, which is a noun that receives the action of the verb; 
- "frequency rank" is a measure of how often a sentence is used, with lower ranks indicating higher frequency.

sql:
SELECT sentence_id, DOsentence || ' ' || PDsentence AS sentence_structure
FROM sentences
WHERE frequency_rank = (
    SELECT MAX(frequency_rank)
    FROM sentences
);
